import{j as i}from"./vendor-react-BB9tsc3Z.js";import{M as o}from"./MobilePageLayout-BAnSXXtz.js";import"./vendor-misc-CEWPm66Y.js";import"./index-CBrXAMbW.js";import"./vendor-router-DqG_9oXp.js";import"./vendor-icons-DCGlAsJ-.js";import"./vendor-motion-CJwlNdkI.js";import"./vendor-socket-CmWqgDFt.js";const s={subtitle:"আমাদের তথ্য কেন্দ্রে স্বাগতম",title:"JowaBuzz নিরাপত্তা",intro:["আপনার তথ্য আমাদের কাছে নিরাপদ থাকে তা নিশ্চিত করার জন্য আমরা সর্বাধিক উপলব্ধ উপায়গুলি বজায় রাখি। সমস্ত তথ্য এনক্রিপশন প্রযুক্তি ব্যবহার করে স্থানান্তরিত করা হয় এবং একবার আমাদের সার্ভারে সংরক্ষণ করা হলে, এটি আজকের উপলব্ধ সর্বশেষ ফায়ারওয়াল প্রযুক্তি ব্যবহার করে নিরাপদ রাখা হয়। আমাদের ওয়েব সাইট এবং সফটওয়্যার উভয়ই ডেটার নির্ভুলতা এবং গোপনীয়তা বজায় রাখার জন্য এবং আপনার ডেটা অপব্যবহার এবং/অথবা হারিয়ে যাওয়া থেকে রক্ষা করার জন্য সমস্ত উপলব্ধ উপায় ব্যবহার করে।","আপনার যদি ডেটা গোপনীয়তা এবং নিরাপত্তা সংক্রান্ত অন্য কোনো প্রশ্ন বা উদ্বেগ থাকে, তবে দয়া করে আমাদের গ্রাহক সহায়তার সাথে যেকোনো সময়, দিনে ২৪ ঘণ্টা এবং সপ্তাহে ৭ দিন যোগাযোগ করতে দ্বিধা করবেন না। আমাদের কাস্টমার সাপোর্ট প্রতিনিধিরা আপনাকে সাহায্য করতে পেরে খুশি হবেন।"],sections:[{id:"cookie-policy",title:"কুকিজ নীতি",paragraphs:["JowaBuzz-এর লক্ষ্য হলো আপনাকে সর্বদা সর্বোত্তম পরিষেবা এবং ব্যবহারকারীর অভিজ্ঞতা প্রদান করা। এটি প্রদান করার আমাদের উপায়গুলোর মধ্যে একটি হলো কুকিজ ব্যবহার করা।"]},{id:"how-cookies",title:"JowaBuzz কিভাবে কুকিজ ব্যবহার করে",paragraphs:["সাধারণত, JowaBuzz ব্যবহারকারীর অভিজ্ঞতা উন্নত করতে কুকি ব্যবহার করে। আপনাকে আরও ভালো দৃষ্টিভঙ্গি ও বোঝার জন্য, আমরা আমাদের ওয়েবসাইটে কীভাবে কুকিজ ব্যবহার করা হয় তা নীচে সরবরাহ করেছি।"]},{id:"tracking",title:"ট্র্যাকিং এবং বিশ্লেষণ",items:["আমাদের ওয়েবসাইট পরিষেবাগুলোকে আরও উন্নত করতে ওয়েবসাইট ট্রাফিক বিশ্লেষণ করতে কুকিজ ব্যবহার করা হয়।","JowaBuzz অ্যাফিলিয়েট প্রোগ্রামের জন্য ব্যবহৃত তথ্য সংগ্রহ করতে ব্যবহৃত হয়।","ব্যবহারকারীরা কীভাবে ওয়েবসাইটের ভিতরে চলাচল করে এবং দর্শকরা কীভাবে আমাদের সাইট ব্যবহার করে সে সম্পর্কে তথ্য সংগ্রহ করা হয়। JowaBuzz এই তথ্য ব্যবহার করে রিপোর্ট তৈরি করে এবং আমাদের পরিষেবা উন্নত করতে সাহায্য করে।"]},{id:"functionality",title:"কার্যকারিতা",items:["এটি আমাদের আপনাকে প্রত্যাবর্তনকারী দর্শক হিসেবে চিনতে এবং আপনার পছন্দের বিষয়বস্তু প্রদর্শন করতে দেয়।","আমাদের প্রদত্ত পরিষেবার অভিজ্ঞতা বাড়িয়ে তুলতে ব্যবহার করা হয়।","আমাদের দর্শকদের সহায়তা প্রদানের জন্য অনলাইন চ্যাট পরিষেবার জন্য কুকিজ ব্যবহার করা হয়।","JowaBuzz বিশেষ করে সেশন এবং ক্রমাগত কুকিজ ব্যবহার করে। সেশন কুকি সেশন লগআউটের পরে মেয়াদ শেষ হয়ে যায় এবং স্থায়ী কুকি নির্দিষ্ট ধরনের কুকিজের উপর নির্ভর করে আপনার ব্রাউজারে এক মিনিট থেকে এক বছর পর্যন্ত সংরক্ষণ করা যায়।"]},{id:"manage-cookies",title:"কিভাবে কুকিজ পরিচালনা করবেন",paragraphs:["আপনি আপনার ব্রাউজার কনফিগার করতে পারেন যদি আপনি কুকিজ অক্ষম, মুছে ফেলতে বা আপনার ব্রাউজারের গোপনীয়তা সেটিং পরিবর্তন করে আপনার কম্পিউটারে কুকিজ সংরক্ষণ বন্ধ করতে চান। তবে দয়া করে মনে রাখবেন যে কুকিজ নিষ্ক্রিয় করা আমাদের দেওয়া কিছু পরিষেবা বা বৈশিষ্ট্যকে প্রভাবিত করতে পারে।"]},{id:"official",title:"JowaBuzz অফিসিয়াল",paragraphs:["অনুগ্রহ করে লাইসেন্সবিহীন এবং অনিয়ন্ত্রিত সত্তা থেকে সতর্ক থাকুন যারা দূষিত উদ্দেশ্য নিয়ে JowaBuzz ওয়েবসাইটের প্রতিলিপি করার চেষ্টা করছে। এই ভুয়া ওয়েবসাইটগুলো JowaBuzz-এর সাথে কোনোভাবেই যুক্ত নয় এবং আমাদের নিয়ন্ত্রণ ও সুরক্ষার বাইরে। সর্বোচ্চ নিরাপত্তার মানের জন্য, শুধুমাত্র অফিসিয়াল JowaBuzz ওয়েবসাইটে খেলুন।"]}]};function l({items:e}){return i.jsx("ul",{className:"info-page-section__list",children:e.map(t=>i.jsx("li",{children:t},t.slice(0,32)))})}function n(){return i.jsxs("section",{className:"info-page-section","aria-labelledby":"security-title",children:[i.jsxs("div",{className:"info-page-section__head",children:[i.jsx("p",{className:"info-page-section__subtitle",children:s.subtitle}),i.jsx("h1",{id:"security-title",className:"info-page-section__title",children:s.title}),i.jsx("div",{className:"info-page-section__divider","aria-hidden":"true"})]}),i.jsxs("div",{className:"info-page-section__body info-page-section__body--left",children:[s.intro.map(e=>i.jsx("p",{className:"info-page-section__text",children:e},e.slice(0,32))),s.sections.map(e=>{var t;return i.jsxs("article",{className:"info-page-section__article",children:[i.jsx("h2",{className:"info-page-section__heading",children:e.title}),(t=e.paragraphs)==null?void 0:t.map(a=>i.jsx("p",{className:"info-page-section__text",children:a},a.slice(0,32))),e.items?i.jsx(l,{items:e.items}):null]},e.id)})]})]})}function h(){return i.jsx(o,{children:i.jsx("div",{className:"security-page mx-auto w-full max-w-3xl px-4 py-6 md:px-6 md:py-8",children:i.jsx(n,{})})})}export{h as default};
